const j = $input.first().json;
// No $env here: many n8n installs block env access inside Code nodes.
const model = String(j.seedance_model || 'seedance-2-fast').trim() || 'seedance-2-fast';
const rawRes = String(j.seedance_resolution || '480p').trim().toLowerCase() || '480p';
const isFast = model.toLowerCase().includes('fast');
const candidates = isFast ? ['480p', '720p'] : ['480p', '720p', '1080p'];
const resolution = candidates.includes(rawRes) ? rawRes : (isFast ? '480p' : '720p');

const userPrompt = String(j.prompt_visual || '').trim();
const styleFix = 'lo-fi hip hop music video aesthetic, chillhop, soft neon palette, cozy mood, slow smooth camera, subtle 35mm grain, no people faces focus, no readable text, no logos, no watermark, vertical cinematic';
const prompt = [userPrompt, styleFix].filter(Boolean).join(', ');

const tags = String(j.tags || '')
  .split(',')
  .map((t) => t.trim())
  .filter(Boolean);

const shortsCount = Math.max(1, parseInt(String(j.shorts_count || '1'), 10) || 1);
const clipSeconds = Math.max(5, parseInt(String(j.clip_seconds || '30'), 10) || 30);
// PoYo Seedance 2: duration 4–15 seconds (API)
const rawDur = parseInt(String(j.seedance_duration || '15'), 10) || 15;
const duration = Math.min(15, Math.max(4, rawDur));

const rawName = String(j.output_filename || '').trim();
const outputFilename = rawName || `poyo-lofi-hiphop-${Date.now()}.mp4`;

const trackMeta = String(j.track_for_metadata || '').trim() || null;
const theme = String(j.theme || 'Lo-fi Hip Hop').trim();
const privacy = String(j.shorts_privacy_status || 'public').trim() || 'public';

return [{
  json: {
    poyo_payload: {
      model,
      input: {
        prompt,
        aspect_ratio: '9:16',
        resolution,
        duration,
        generate_audio: false,
      },
    },
    output_filename: outputFilename,
    track_for_metadata: trackMeta,
    theme,
    tags,
    publish_at_iso: new Date().toISOString(),
    shorts_count: shortsCount,
    short_delay_hours: 0,
    short_interval_hours: 24,
    clip_seconds: clipSeconds,
    shorts_privacy_status: privacy,
    cleanup_source_after_publish: true,
    cleanup_shorts_after_upload: true,
  },
}];
